set -e
# 增量更新 cloud server：解码 → 解包到 /opt/temu-cloud → systemd restart
cat > /tmp/cloud-update.b64 <<'B64EOF'

B64EOF
base64 -d /tmp/cloud-update.b64 > /tmp/cloud-update.tar.gz
sudo tar xzf /tmp/cloud-update.tar.gz -C /opt/temu-cloud --strip-components=1
sudo chown -R $(whoami):$(whoami) /opt/temu-cloud
echo '--- 跑一遍迁移（如果有新表会自动加） ---'
cd /opt/temu-cloud && node -e "import('./db/migrate.js').then(m=>m.migrate()).then(r=>console.log('migrated:',r))"
echo '--- 重启 systemd ---'
sudo systemctl restart temu-cloud
sleep 2
echo '--- 验证 ---'
curl -s http://localhost:8788/api/_meta | head -1
echo '完成。返回桌面端打开「多店云监控 → 可视化」tab 看图表'
